+/// Resolve the in-memory time-travel snapshot that satisfies the requested
+/// historical target.
+///
+/// Snapshots are appended in commit order and retain a monotonic timestamp
+/// discipline, so both commit-sequence and timestamp lookups can use binary
+/// search over the retained snapshot ring.
+fn resolve_time_travel_snapshot_entry<'a>(
+    snaps: &'a [TimeTravelSnapshotEntry],
+    target: &TimeTravelTarget,
+) -> Result<&'a TimeTravelSnapshotEntry> {
+    let resolved = match target {
+        TimeTravelTarget::CommitSequence(seq) => snaps
+            .binary_search_by_key(seq, |snapshot| snapshot.commit_seq)
+            .ok()
+            .and_then(|idx| snaps.get(idx)),
+        TimeTravelTarget::Timestamp(ts_str) => {
+            let target_ns = parse_timestamp_to_ns(ts_str)?;
+            let upper_bound = snaps.partition_point(|snapshot| snapshot.timestamp_ns <= target_ns);
+            upper_bound.checked_sub(1).and_then(|idx| snaps.get(idx))
+        }
+    };
+
+    resolved.ok_or_else(|| {
+        FrankenError::Internal(format!(
+            "time-travel: no snapshot available for {}",
+            format_time_travel_target(target),
+        ))
+    })
+}
